export function scale(image: string[], scaleFactor: number): string[] {
  if (image.length === 0) {
    return [];
  }

  const isSinglePixel = image.length === 1 && image[0].length === 1;

  if (isSinglePixel) {
    // Scale single pixel vertically
    return duplicateLines(image, scaleFactor);
  }

  const isMultiRowMultiCol = image.length > 1 && image[0].length > 1;

  if (isMultiRowMultiCol) {
    // Scale both horizontally and vertically
    const horizontallyScaled = scaleHorizontalLines(image, scaleFactor);
    return duplicateLines(horizontallyScaled, scaleFactor);
  }

  const isSingleColumn = image.length > 1 && image.every((line) => line.length === 1);

  if (isSingleColumn) {
    // Scale vertically only
    return duplicateLines(image, scaleFactor);
  }

  // Default: scale horizontally only
  return scaleHorizontalLines(image, scaleFactor);
}
